// 智能内容分析和页面类型判断
const content = $input.first().json;
const url = $('输入参数设置').first().json.url;
const sceneCount = parseInt($('输入参数设置').first().json.scene_count);
const videoStyle = $('输入参数设置').first().json.video_style;
const voiceLanguage = $('输入参数设置').first().json.voice_language;

// 提取和清理文本内容
function cleanText(text) {
  if (!text) return '';
  return text.replace(/\s+/g, ' ').replace(/[\r\n]+/g, ' ').trim();
}

// 判断页面类型
function detectPageType(url, title, content) {
  const urlLower = url.toLowerCase();
  const titleLower = (title || '').toLowerCase();
  const contentLower = content.toLowerCase();

  // 电商平台检测
  const ecommercePatterns = [
    'amazon', 'taobao', 'tmall', 'jd.com', 'shopify', 'alibaba',
    'ebay', 'walmart', 'target', 'bestbuy', '购买', '商品', 'product',
    'shop', 'store', 'buy', 'price', '$', '¥', '€', '£', 'cart', 'checkout'
  ];

  // 新闻平台检测
  const newsPatterns = [
    'news', 'article', 'report', 'breaking', '新闻', '报道', 
    'headline', 'story', 'press', 'media', '今日', '昨日', 'reuters', 'bbc', 'cnn'
  ];

  let ecommerceScore = 0;
  let newsScore = 0;

  ecommercePatterns.forEach(pattern => {
    if (urlLower.includes(pattern) || titleLower.includes(pattern) || contentLower.includes(pattern)) {
      ecommerceScore++;
    }
  });

  newsPatterns.forEach(pattern => {
    if (urlLower.includes(pattern) || titleLower.includes(pattern) || contentLower.includes(pattern)) {
      newsScore++;
    }
  });

  if (ecommerceScore > newsScore) return 'ecommerce';
  if (newsScore > ecommerceScore) return 'news';
  return 'general';
}

// 提取关键信息
const title = cleanText(content.title);
const description = cleanText(content.description);
const price = cleanText(content.price);
const features = cleanText(content.features);
const fullContent = cleanText(content.content);

// 判断页面类型
const pageType = detectPageType(url, title, fullContent);

// 根据页面类型生成不同的提示词
let extractionPrompt = '';

if (pageType === 'ecommerce') {
  extractionPrompt = `请分析以下电商商品页面内容，提取关键信息：\n\n标题：${title}\n描述：${description}\n价格：${price}\n特性：${features}\n\n请提取以下信息并以JSON格式返回：\n1. 产品名称 (product_name)\n2. 主要特性 (main_features) - 数组格式\n3. 价格信息 (price_info)\n4. 目标用户 (target_audience)\n5. 产品优势 (advantages) - 数组格式\n6. 使用场景 (use_cases) - 数组格式`;
} else if (pageType === 'news') {
  extractionPrompt = `请分析以下新闻页面内容，提取关键信息：\n\n标题：${title}\n内容：${fullContent.substring(0, 2000)}\n\n请提取以下信息并以JSON格式返回：\n1. 新闻标题 (news_title)\n2. 主要事件 (main_event)\n3. 关键人物 (key_people) - 数组格式\n4. 时间地点 (time_location)\n5. 重要细节 (important_details) - 数组格式\n6. 影响分析 (impact_analysis)`;
} else {
  extractionPrompt = `请分析以下网页内容，提取关键信息：\n\n标题：${title}\n描述：${description}\n内容：${fullContent.substring(0, 2000)}\n\n请提取以下信息并以JSON格式返回：\n1. 主题 (main_topic)\n2. 关键点 (key_points) - 数组格式\n3. 目标受众 (target_audience)\n4. 核心信息 (core_message)\n5. 相关细节 (related_details) - 数组格式`;
}

return {
  page_type: pageType,
  url: url,
  raw_content: {
    title: title,
    description: description,
    price: price,
    features: features,
    content: fullContent.substring(0, 3000)
  },
  extraction_prompt: extractionPrompt,
  scene_count: sceneCount,
  video_style: videoStyle,
  voice_language: voiceLanguage
};

// 生成分镜脚本
const aiResponse = $input.first().json;
const analysisData = $('内容分析与类型判断').first().json;

let extractedInfo = '';
if (Array.isArray(aiResponse) && aiResponse.length > 0) {
  extractedInfo = aiResponse[0].generated_text || JSON.stringify(analysisData.raw_content);
} else if (aiResponse && aiResponse.generated_text) {
  extractedInfo = aiResponse.generated_text;
} else {
  extractedInfo = JSON.stringify(analysisData.raw_content);
}

// 根据页面类型生成分镜脚本
const pageType = analysisData.page_type;
const sceneCount = analysisData.scene_count;
const videoStyle = analysisData.video_style;
const voiceLanguage = analysisData.voice_language;

// 创建分镜
const scenes = [];
for (let i = 1; i <= sceneCount; i++) {
  let sceneDescription = '';
  let narration = '';

  if (pageType === 'ecommerce') {
    const productName = analysisData.raw_content.title || '商品';
    sceneDescription = `专业商品展示场景${i}，展示${productName}的特色和优势，高质量商业摄影风格`;
    narration = `第${i}个场景：展示${productName}的核心特性和优势`;
  } else if (pageType === 'news') {
    const newsTitle = analysisData.raw_content.title || '新闻事件';
    sceneDescription = `新闻报道场景${i}，客观展示${newsTitle}相关内容，专业新闻摄影风格`;
    narration = `第${i}个场景：报道${newsTitle}的重要信息`;
  } else {
    const mainTopic = analysisData.raw_content.title || '主要内容';
    sceneDescription = `内容展示场景${i}，传达${mainTopic}的核心信息，专业演示风格`;
    narration = `第${i}个场景：介绍${mainTopic}的关键要点`;
  }

  // 风格映射
  const styleMapping = {
    '专业商务': 'professional business style, clean corporate aesthetic, high-quality product photography, studio lighting',
    '活泼轻松': 'vibrant and playful style, bright colors, energetic composition, dynamic lighting',
    '高端奢华': 'luxury premium style, elegant sophisticated aesthetic, high-end fashion photography, dramatic lighting',
    '简约现代': 'minimalist modern style, clean lines, contemporary design, soft natural lighting'
  };

  const stylePrompt = styleMapping[videoStyle] || 'professional style, high quality, detailed';

  scenes.push({
    scene_number: i,
    image_prompt: `${sceneDescription}, ${stylePrompt}, cinematic composition, 4K quality, ultra detailed, photorealistic`,
    narration: narration,
    duration: 5,
    camera_movement: i % 3 === 0 ? 'slow zoom in' : (i % 3 === 1 ? 'pan right' : 'steady shot'),
    style_notes: videoStyle
  });
}

return {
  scenes: scenes,
  total_scenes: scenes.length,
  video_style: videoStyle,
  voice_language: voiceLanguage,
  page_type: pageType,
  original_url: analysisData.url,
  extracted_info: extractedInfo
};

// 处理图像生成成功的情况
const imageData = $input.first().binary;
const sceneData = $('分镜处理循环').first().json;

return {
  scene_number: sceneData.scene_number,
  image_data: imageData,
  narration: sceneData.narration,
  duration: sceneData.duration,
  camera_movement: sceneData.camera_movement,
  status: 'success',
  image_prompt: sceneData.image_prompt,
  style_notes: sceneData.style_notes
};

// 处理图像生成失败的情况
const sceneData = $('分镜处理循环').first().json;
const retryCount = parseInt($node['输入参数设置'].json.retry_count) || 0;

if (retryCount >= 3) {
  return {
    scene_number: sceneData.scene_number,
    status: 'failed',
    error: 'Maximum retry attempts reached for image generation',
    image_prompt: sceneData.image_prompt,
    narration: sceneData.narration,
    duration: sceneData.duration,
    retry_count: retryCount
  };
}

return {
  scene_number: sceneData.scene_number,
  status: 'retry',
  retry_count: retryCount + 1,
  image_prompt: sceneData.image_prompt,
  narration: sceneData.narration,
  duration: sceneData.duration,
  camera_movement: sceneData.camera_movement
};

