// 收集分镜数据
const videoResult = $('获取视频结果').first()?.json;
const audioResult = $('生成配音').first()?.binary;
const sceneData = $('分镜处理循环').first().json;

const result = {
  scene_number: sceneData.scene_number,
  video_url: videoResult?.output?.url || videoResult?.url || null,
  audio_data: audioResult || null,
  narration: sceneData.narration,
  duration: sceneData.duration,
  camera_movement: sceneData.camera_movement,
  status: 'completed',
  generation_id: videoResult?.id || null
};

return result;

// 生成最终结果
const allScenes = $input.all();
const projectData = $node['生成分镜脚本'].json;

// 过滤和统计
const successfulScenes = allScenes.filter(scene => 
  scene.json.status === 'completed' || scene.json.status === 'success'
);
const failedScenes = allScenes.filter(scene => 
  scene.json.status === 'failed'
);

if (successfulScenes.length === 0) {
  return {
    status: 'error',
    message: '所有分镜生成失败，请检查API配置和网络连接',
    failed_count: failedScenes.length,
    total_scenes: projectData.total_scenes
  };
}

// 按场景编号排序
successfulScenes.sort((a, b) => a.json.scene_number - b.json.scene_number);

// 准备场景结果
const sceneResults = successfulScenes.map(scene => ({
  scene_number: scene.json.scene_number,
  video_url: scene.json.video_url,
  narration: scene.json.narration,
  duration: scene.json.duration,
  camera_movement: scene.json.camera_movement,
  status: 'completed',
  has_audio: !!scene.json.audio_data,
  generation_id: scene.json.generation_id
}));

// 生成项目摘要
const summary = {
  project_name: `视频项目-${new Date().toISOString().split('T')[0]}`,
  total_scenes: projectData.total_scenes,
  successful_scenes: successfulScenes.length,
  failed_scenes: failedScenes.length,
  success_rate: (successfulScenes.length / projectData.total_scenes * 100).toFixed(2) + '%',
  original_url: projectData.original_url,
  page_type: projectData.page_type,
  video_style: projectData.video_style,
  voice_language: projectData.voice_language,
  total_duration: successfulScenes.length * 5 + ' seconds',
  estimated_file_size: (successfulScenes.length * 15).toFixed(1) + ' MB'
};

// 生成下载链接和说明
const downloadInstructions = {
  video_segments: sceneResults.map(scene => ({
    scene: scene.scene_number,
    download_url: scene.video_url,
    filename: `scene_${scene.scene_number.toString().padStart(2, '0')}.mp4`
  })),
  composition_guide: [
    '1. 下载所有视频片段到本地',
    '2. 使用视频编辑软件（如 Premiere、Final Cut Pro、DaVinci Resolve）',
    '3. 按场景编号顺序排列片段',
    '4. 添加转场效果（建议使用淡入淡出）',
    '5. 调整音频音量平衡',
    '6. 添加背景音乐（可选）',
    '7. 导出最终视频（建议1080p，30fps）'
  ],
  recommended_settings: {
    resolution: '1920x1080',
    frame_rate: '30fps',
    bitrate: '8-12 Mbps',
    audio_bitrate: '320 kbps',
    format: 'MP4 (H.264)'
  }
};

return {
  status: 'completed',
  message: `视频项目完成！成功生成 ${successfulScenes.length}/${projectData.total_scenes} 个分镜`,
  summary: summary,
  scenes: sceneResults,
  downloads: downloadInstructions,
  timestamp: new Date().toISOString(),
  next_steps: [
    '下载所有视频片段',
    '使用专业视频编辑软件合成',
    '添加字幕和特效（可选）',
    '导出并发布最终视频'
  ],
  api_usage: {
    huggingface_calls: projectData.total_scenes + 1,
    video_generation_calls: successfulScenes.length,
    audio_generation_calls: successfulScenes.length
  }
};

